import { trpc } from '../utils/trpc';

export default function Home() {
  const hello = trpc.hello.useQuery('tRPC v11');

  if (hello.isLoading) return <div>Loading...</div>;
  if (hello.isError) return <div>Error: {hello.error.message}</div>;

  return (
    <main>
      <h1>{hello.data}</h1>
    </main>
  );
}

